mapper.select:
SELECT A.*, CASE WHEN A.CNT = 0 THEN '2' WHEN (A.ATTEND_CNT/A.CNT)*100 >= 70 THEN '1' ELSE '2' END AS STUDENT_STATUS FROM ( SELECT a.STUDENT_IDX, a.STUDENT_NAME as MEMBER_NAME, a.STUDENT_ADDRESS, a.STUDENT_ADDRESS_DETAIL, a.STUDENT_BIRTH, a.STUDENT_OLD, REGEXP_REPLACE(a.APPLICANT_CELL_PHONE,'([[:digit:]]{3})([[:digit:]]{3,4})([[:digit:]]{4})','\1-\2-\3') AS MEMBER_PHONE , (SELECT TEACH_COUNT FROM TEACH WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX) AS CNT , (SELECT NVL(SUM(DECODE(status, '1', 1, '2', 1, 0)) - TRUNC(SUM(DECODE(status, '2', 1, 0))/3), 0) FROM TEACH_BOOK WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TEACH_IDX = a.TEACH_IDX AND STUDENT_IDX = a.STUDENT_IDX) as ATTEND_CNT, a.MEMBER_ID, a.member_key FROM STUDENT a WHERE a.DELETE_YN = 'N' AND a.HOMEPAGE_ID = #{homepage_id}
AND a.GROUP_IDX = #{codeList_2}
AND a.CATEGORY_IDX = #{codeList_3}
AND a.TEACH_IDX = #{codeList_4}
AND a.APPLY_STATUS = '1'
AND a.APPLY_STATUS = '2'
AND a.APPLY_STATUS = '99'
ORDER BY a.ADD_DATE DESC ) A

SELECT
	A.EXCURSIONS_IDX AS CODE_ID_5,
	TO_CHAR(TO_DATE(A.START_DATE,'YYYY-MM-DD'),'DD') || '일' AS CODE_NAME_5
FROM
	CMS_EXCURSIONS A
WHERE 1=1
	AND A.HOMEPAGE_ID = #{homepage_id}
	AND TO_CHAR(TO_DATE(A.START_DATE,'YYYY-MM-DD'),'YYYY') = #{codeList_3} 
	AND TO_CHAR(TO_DATE(A.START_DATE,'YYYY-MM-DD'),'MM') = #{codeList_4}

SELECT APPLICANT_NAME AS MEMBER_NAME, APPLICANT_TEL AS MEMBER_PHONE, AGENCY_NAME AS IMSI_V_1, APPLICANT_MEMBER_ID AS MEMBER_ID, MEMBER_KEY FROM CMS_EXCURSIONS_APPLY WHERE HOMEPAGE_ID = #{homepage_id}
AND TO_CHAR(TO_DATE(START_DATE,'YYYY-MM-DD'),'YYYY') = #{codeList_3}
AND TO_CHAR(TO_DATE(START_DATE,'YYYY-MM-DD'),'MM') = #{codeList_4}
AND EXCURSIONS_IDX = #{codeList_5}
AND APPLY_STATE = 3
AND APPLY_STATE = 1

SELECT REQUER_NAME AS MEMBER_NAME, REQUER_TEL AS MEMBER_PHONE, REQ_NAME AS IMSI_V_1, REQ_ID AS MEMBER_ID, MEMBER_KEYT FROM FIELD_SUPPORT WHERE 1=1 AND HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND TO_CHAR(hope_req_dt,'YYYY') = #{codeList_2} AND TO_CHAR(hope_req_dt,'MM') = #{codeList_3} AND TO_CHAR(hope_req_dt,'DD') = #{codeList_4}
AND PROCESS_STATE = 'Y'
AND PROCESS_STATE = 'N'

${pagingTop} SELECT BOX_IDX AS IMSI_V_1, TITLE AS IMSI_V_2, CONTENTS AS IMSI_V_3, TO_CHAR(ADD_DATE,'YYYY-MM-DD') AS IMSI_V_4 FROM CMS_SMS_BOX WHERE 1=1 AND HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND USE_YN = 'Y'
AND ${search_type} like '%' || #{search_text} || '%'
ORDER BY ADD_DATE ${pagingBottom}
